SELECT message_id, sender_name, receiver_name, title, content, send_date, read_date, status FROM erp_message
AND (title LIKE '%' || #{keyword} || '%' OR sender_name LIKE '%' || #{keyword} || '%' OR receiver_name LIKE '%' || #{keyword} || '%')
ORDER BY send_date DESC LIMIT #{limit} OFFSET #{offset}
